import React from 'react';
import { Formik, Form, Field, ErrorMessage } from 'formik';
import * as Yup from 'yup';
import axios from 'axios';
import './RegisterModal.scss';

const RegisterModal = ({ onClose }) => {
  const initialValues = {
    email: '',
    password: '',
    confirmPassword: '',
  };

  const validationSchema = Yup.object({
    email: Yup.string().email('Invalid email format').required('Required'),
    password: Yup.string().required('Required'),
    confirmPassword: Yup.string()
      .oneOf([Yup.ref('password'), null], 'Passwords must match')
      .required('Required'),
  });

  const onSubmit = (values, { setSubmitting, setErrors }) => {
    axios.post('http://localhost:5000/register', {
      email: values.email,
      password: values.password,
    })
      .then(response => {
        // Handle success
        console.log('Registration successful:', response.data);
        // You might want to close the modal or redirect the user here
        onClose(); // Close the modal
      })
      .catch(error => {
        // Handle error
        console.error('Registration error:', error);
        setErrors({ email: 'Email already exists or other error' }); // Set a generic error message
      })
      .finally(() => {
        setSubmitting(false);
      });
  };

  return (
    <div className="register-modal">
      <div className="modal-content">
        <button className="close-button" onClick={onClose}>&times;</button>
        <h1 className="register-modal__title">Register</h1>
        <Formik initialValues={initialValues} validationSchema={validationSchema} onSubmit={onSubmit}>
          {({ isSubmitting }) => (
            <Form className="register-modal__form">
              <div className="register-modal__form-group">
                <label htmlFor="email" className="register-modal__label">Email</label>
                <Field type="email" id="email" name="email" className="register-modal__input" />
                <ErrorMessage name="email" component="div" className="register-modal__error" />
              </div>
              <div className="register-modal__form-group">
                <label htmlFor="password" className="register-modal__label">Password</label>
                <Field type="password" id="password" name="password" className="register-modal__input" />
                <ErrorMessage name="password" component="div" className="register-modal__error" />
              </div>
              <div className="register-modal__form-group">
                <label htmlFor="confirmPassword" className="register-modal__label">Confirm Password</label>
                <Field type="password" id="confirmPassword" name="confirmPassword" className="register-modal__input" />
                <ErrorMessage name="confirmPassword" component="div" className="register-modal__error" />
              </div>
              <button type="submit" className="register-modal__submit-button" disabled={isSubmitting}>
                Register
              </button>
            </Form>
          )}
        </Formik>
      </div>
    </div>
  );
};

export default RegisterModal;
